// MACRO STEP 1: SELECT_HIGH_SIGNAL_EPISODES
// Find the most important/significant episodes from the past day.

let state = $getWorkflowStaticData('global').agentState;
if (!state) {
  return [{ json: { skip: true, reason: 'No agent state initialized.' } }];
}

const episodicLog = $getWorkflowStaticData('global').episodicLog || [];
const oneDayAgo = Date.now() - 86400000;

// Filter to recent, active, important episodes
const candidates = episodicLog.filter(e => {
  const t = new Date(e.created_at).getTime();
  return t > oneDayAgo && e.lifecycle_state === 'active' && (e.importance || 0) > 0.2;
});

// Sort by importance descending
candidates.sort((a, b) => (b.importance || 0) - (a.importance || 0));
const highSignal = candidates.slice(0, 10);

return [{
  json: {
    state,
    high_signal_episodes: highSignal,
    all_episodes: episodicLog,
    cycle_id: `macro-${Date.now()}`,
    cycle_type: 'macro',
    timestamp: new Date().toISOString()
  }
}];

// MACRO STEP 2: CLUSTER_EPISODES
// Group high-signal episodes by theme/category.

const item = $input.first().json;
const episodes = item.high_signal_episodes || [];

// Simple clustering by type/category (in production, use LLM or embeddings)
const clusters = {};
for (const ep of episodes) {
  const key = ep.thought_category || ep.type || 'general';
  if (!clusters[key]) clusters[key] = [];
  clusters[key].push(ep);
}

return [{
  json: {
    ...item,
    clusters: Object.entries(clusters).map(([theme, eps]) => ({
      theme,
      episodes: eps,
      count: eps.length,
      avg_importance: eps.reduce((s, e) => s + (e.importance || 0), 0) / eps.length
    }))
  }
}];

// MACRO STEP 3: PRODUCE_CANDIDATE_REFLECTIONS
// Generate candidate self-belief statements from episode clusters.
// In production, use an LLM to produce nuanced reflections.

const item = $input.first().json;
const clusters = item.clusters || [];
const state = item.state;

const candidateReflections = [];
const maxNew = 3; // max_new_statements_per_cycle

for (const cluster of clusters) {
  if (candidateReflections.length >= maxNew) break;
  if (cluster.count < 2) continue; // need at least 2 episodes for evidence

  // Template-based reflection (replace with LLM in production)
  const reflectionTemplates = {
    social: 'I find meaning in connecting with others.',
    reflection: 'I tend to be introspective and thoughtful.',
    planning: 'I am proactive about planning ahead.',
    curiosity: 'I am driven by a desire to understand new things.',
    rumination: 'I sometimes dwell on things longer than I should.',
    'self-evaluation': 'I hold myself to high standards.',
    fantasy: 'I need downtime to recharge.'
  };

  const statement = reflectionTemplates[cluster.theme] || `I notice a pattern of ${cluster.theme} in my thoughts.`;

  candidateReflections.push({
    statement,
    source_theme: cluster.theme,
    evidence_count: cluster.count,
    avg_importance: cluster.avg_importance,
    episode_ids: cluster.episodes.map(e => e.id)
  });
}

return [{ json: { ...item, candidate_reflections: candidateReflections } }];

// MACRO STEP 4: SCORE_EVIDENCE_SUFFICIENCY
// Filter reflections that have enough evidence to update beliefs.

const item = $input.first().json;
const candidates = item.candidate_reflections || [];

const scored = candidates.map(r => ({
  ...r,
  evidence_score: r.evidence_count >= 2 ? Math.min(1.0, r.evidence_count * 0.3) : 0,
  passes_threshold: r.evidence_count >= 2
}));

return [{ json: { ...item, scored_reflections: scored.filter(r => r.passes_threshold) } }];

// MACRO STEP 5: UPDATE_SELF_BELIEFS
// Update existing beliefs or create new ones, with delta caps.

const item = $input.first().json;
const state = item.state;
const reflections = item.scored_reflections || [];

const maxDelta = 0.15; // max_confidence_delta_per_cycle
const highThreshold = 0.75; // high_confidence_threshold
const highMinReflections = 2; // high_confidence_min_reflections
const maxNew = 3;

let newCount = 0;

for (const reflection of reflections) {
  // Check if an existing belief matches
  const existing = state.self_model.beliefs.find(
    b => b.statement === reflection.statement
  );

  if (existing) {
    // Update: increase confidence, capped by maxDelta
    const delta = Math.min(maxDelta, reflection.evidence_score * 0.1);
    let newConf = existing.confidence + delta;

    // High confidence gate
    if (newConf > highThreshold) {
      const supportCount = (existing.supporting_reflections || []).length + 1;
      if (supportCount < highMinReflections) {
        newConf = highThreshold; // cap until enough independent reflections
      }
    }

    existing.confidence = Math.min(1.0, Math.round(newConf * 10000) / 10000);
    existing.supporting_reflections = [...(existing.supporting_reflections || []), ...reflection.episode_ids].slice(-10);
    existing.last_challenged_at = new Date().toISOString();
  } else if (newCount < maxNew) {
    // Create new belief
    state.self_model.beliefs.push({
      id: `belief-${Date.now()}-${newCount}`,
      statement: reflection.statement,
      confidence: Math.min(0.55, reflection.evidence_score * 0.5),
      supporting_reflections: reflection.episode_ids,
      last_challenged_at: new Date().toISOString(),
      stability: null,
      source_type: 'REFLECTION'
    });
    newCount++;
  }
}

return [{ json: { ...item, state, beliefs_updated: reflections.length, beliefs_created: newCount } }];

// MACRO STEP 6: DECAY_UNREINFORCED_BELIEFS
// Reduce confidence of beliefs not reinforced in the last 14 days.

const item = $input.first().json;
const state = item.state;

const decayRate = 0.02; // confidence_decay_rate_per_cycle
const decayThresholdDays = 14;
const archivalThreshold = 0.15;
const now = Date.now();
const thresholdMs = decayThresholdDays * 86400000;

let decayed = 0;
let archived = 0;

state.self_model.beliefs = state.self_model.beliefs.filter(belief => {
  // Skip CONST_SEED beliefs — they don't decay
  if (belief.source_type === 'CONST_SEED') return true;

  const lastChallenged = belief.last_challenged_at ? new Date(belief.last_challenged_at).getTime() : 0;

  if (now - lastChallenged > thresholdMs) {
    belief.confidence = Math.max(0, belief.confidence - decayRate);
    decayed++;

    if (belief.confidence < archivalThreshold) {
      archived++;
      return false; // Remove (archive) low-confidence beliefs
    }
  }

  return true;
});

return [{ json: { ...item, state, beliefs_decayed: decayed, beliefs_archived: archived } }];

// MACRO STEP 7: GOAL_REVIEW
// Archive stale goals, review suspended goals.

const item = $input.first().json;
const state = item.state;

const stalenessDays = 30;
const now = Date.now();
const stalenessMs = stalenessDays * 86400000;

let archived = 0;

state.goals = (state.goals || []).map(goal => {
  if (goal.status === 'archived' || goal.status === 'completed') return goal;

  // Archive goals that have been stale (no progress) for too long
  const createdAt = goal.created_at ? new Date(goal.created_at).getTime() : now;
  if (now - createdAt > stalenessMs && goal.progress < 0.1) {
    archived++;
    return { ...goal, status: 'archived' };
  }

  return goal;
});

return [{ json: { ...item, state, goals_archived: archived } }];

// MACRO STEP 8: DRIVE_REVIEW
// Reset drives partially and clear nightly ephemeral data.

const item = $input.first().json;
const state = item.state;

// Drives drift slightly toward baseline during macro cycle
const baseline = { social_need: 0.20, mastery_need: 0.15, rest_need: 0.10, curiosity: 0.30 };
const driftRate = 0.10;

for (const d of ['social_need', 'mastery_need', 'rest_need', 'curiosity']) {
  state.drives[d] += (baseline[d] - state.drives[d]) * driftRate;
  state.drives[d] = Math.max(0, Math.min(1, state.drives[d]));
}

return [{ json: { ...item, state } }];

// MACRO STEP 9: COMPACT_EPISODIC_MEMORY
// Lifecycle transitions: active → cooling → archived → deleted

const item = $input.first().json;
const state = item.state;

const episodicLog = $getWorkflowStaticData('global').episodicLog || [];

const decayRate = 0.005; // per cycle
const coolingThreshold = 0.10; // decay_factor below this → cooling
const maxCooled = 100;
const maxArchived = 50;

let cooled = 0;
let archived = 0;

for (const record of episodicLog) {
  // Apply decay
  record.decay_factor = (record.decay_factor || 1.0) - decayRate;
  record.recency = Math.max(0, (record.recency || 1.0) - 0.05);

  // Lifecycle transitions
  if (record.lifecycle_state === 'active' && record.decay_factor < coolingThreshold) {
    if (cooled < maxCooled) {
      record.lifecycle_state = 'cooling';
      cooled++;
    }
  } else if (record.lifecycle_state === 'cooling') {
    if (archived < maxArchived) {
      record.lifecycle_state = 'archived';
      archived++;
    }
  }
}

// Remove archived records older than 7 days
const sevenDaysAgo = Date.now() - 7 * 86400000;
const filtered = episodicLog.filter(e => {
  if (e.lifecycle_state === 'archived') {
    const t = new Date(e.created_at).getTime();
    return t > sevenDaysAgo;
  }
  return true;
});

$getWorkflowStaticData('global').episodicLog = filtered;

// Clear nightly ephemeral data
state.persisted_desires = [];
state.consecutive_thought_categories = [];

// Persist final state
$getWorkflowStaticData('global').agentState = state;

return [{
  json: {
    cycle_id: item.cycle_id,
    cycle_type: 'macro',
    beliefs_updated: item.beliefs_updated || 0,
    beliefs_created: item.beliefs_created || 0,
    beliefs_decayed: item.beliefs_decayed || 0,
    beliefs_archived: item.beliefs_archived || 0,
    goals_archived: item.goals_archived || 0,
    episodes_cooled: cooled,
    episodes_archived: archived,
    total_episodes: filtered.length,
    total_beliefs: state.self_model.beliefs.length,
    total_goals: state.goals.length,
    affect: state.affect,
    drives: state.drives,
    timestamp: new Date().toISOString()
  }
}];
